+				KDF:          "argon2id",
+				Salt:         "dGVzdHNhbHQ=",
+				Nonce:        "dGVzdG5vbmNl",
+				Argon2Params: DefaultArgon2Params(),
+			},
+			wantErr: false,
+		},
+		{
+			name:    "nil metadata",
+			meta:    nil,
+			wantErr: true,
+		},
+		{
+			name: "unsupported algorithm",
+			meta: &EncryptionMetadata{
+				Version:   1,
+				Algorithm: "aes-128-cbc",
+				KDF:       "argon2id",
+				Salt:      "dGVzdHNhbHQ=",
+				Nonce:     "dGVzdG5vbmNl",
+			},
+			wantErr: true,
+		},
+		{
+			name: "unsupported KDF",
+			meta: &EncryptionMetadata{
+				Version:   1,
+				Algorithm: "aes-256-gcm",
+				KDF:       "pbkdf2",
+				Salt:      "dGVzdHNhbHQ=",
+				Nonce:     "dGVzdG5vbmNl",
+			},
+			wantErr: true,
+		},
+		{
+			name: "missing salt",
+			meta: &EncryptionMetadata{
+				Version:   1,
+				Algorithm: "aes-256-gcm",
+				KDF:       "argon2id",
+				Nonce:     "dGVzdG5vbmNl",
+			},
+			wantErr: true,
+		},
+		{
+			name: "missing nonce",
+			meta: &EncryptionMetadata{
+				Version:   1,
+				Algorithm: "aes-256-gcm",
+				KDF:       "argon2id",
+				Salt:      "dGVzdHNhbHQ=",
+			},
+			wantErr: true,
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			err := ValidateEncryptionMetadata(tt.meta)
+			if (err != nil) != tt.wantErr {
+				t.Errorf("ValidateEncryptionMetadata() error = %v, wantErr %v", err, tt.wantErr)
+			}
+		})
+	}
+}
